   692	        private void serializeTrait(Trait trait) {
   693	            Node node = trait.toNode();
   694	            // We won't fail if the trait can't be found.
   695	            Shape shape = model.getShape(trait.toShapeId()).orElse(null);
   696	
   697	            if (shape != null && (trait instanceof AnnotationTrait || isEmptyStructure(node, shape))) {
   698	                // Traits that inherit from AnnotationTrait specifically can omit a value.
   699	                // Traits that are simply boolean shapes which don't implement AnnotationTrait cannot.
   700	                // Additionally, empty structure traits can omit a value.
   701	                codeWriter.write("@$I", trait.toShapeId());
   702	            } else if (node.isObjectNode()) {
   703	                codeWriter.writeIndent().openBlockInline("@$I(", trait.toShapeId());
   704	                nodeSerializer.serializeKeyValuePairs(node.expectObjectNode(), shape);
   705	                codeWriter.closeBlock(")");
   706	            } else {
   707	                codeWriter.writeIndent().writeInline("@$I(", trait.toShapeId());
   708	                nodeSerializer.serialize(node, shape);
   709	                codeWriter.write(")");
   710	            }
   711	        }
